var selector = (Tekla.Structures.Model.ModelObjectSelector)model.GetModelObjectSelector();
var enumerator = selector.GetAllObjectsWithType(Tekla.Structures.Model.ModelObject.ModelObjectEnum.BEAM);
var result = new System.Collections.Generic.List<object>();
while (enumerator.MoveNext())
{
    var b = (Tekla.Structures.Model.Beam)enumerator.Current;
    double dx = b.EndPoint.X - b.StartPoint.X;
    double dy = b.EndPoint.Y - b.StartPoint.Y;
    double dz = b.EndPoint.Z - b.StartPoint.Z;
    double length = System.Math.Sqrt(dx*dx + dy*dy + dz*dz);
    result.Add(new {
        guid = b.Identifier.GUID.ToString(),
        profile = b.Profile.ProfileString,
        material = b.Material.MaterialString,
        length_mm = System.Math.Round(length, 1),
        klass = b.Class,
        name = b.Name
    });
}
return new { count = result.Count, beams_sample = result.Take(5).ToList() };
